-- flip is_leaf on countries/admin1 that gained children
UPDATE atoms a SET is_leaf=false, updated_at=now()
WHERE a.realm_id='geography' AND a.depth IN (4,5) AND a.path LIKE 'Geography / Countries / Europe / %'
  AND EXISTS (SELECT 1 FROM atoms c WHERE c.path LIKE a.path || ' / %');